#!/usr/bin/env node
/**
 * windswell-analysis.mjs — Windswell conditions for Kanaha / North Shore Maui
 *
 * Analyzes windswell vs groundswell from NDBC spectral data and current wind.
 * Key use case: downwind foilboarding on clean trade-wind-generated swell.
 *
 * Physics:
 *   - Windswell is locally generated by wind blowing over water (fetch + duration + speed)
 *   - Groundswell comes from distant storms, independent of local wind
 *   - Windswell period: 3-8s (short, steep). Groundswell: 10-20s (long, smooth)
 *   - Windswell height depends on: wind speed, fetch distance, wind duration
 *   - Wind direction determines fetch along north shore:
 *       NE (45°): 50nm fetch through Molokai channel — decent windswell
 *       ENE (60-75°): 200nm open Pacific — maximum fetch, best windswell
 *       E (90°): 100nm Alenuihaha Channel — moderate fetch but more cross-shore
 *       ESE/SE: short fetch, land-blocked — minimal windswell
 *   - For downwind foiling, want NE-ENE wind producing swell that runs
 *     parallel to shore / slightly onshore — clean, organized bumps to glide on
 *
 * Outputs JSON to stdout.
 */

import https from 'https';

function fetchText(url) {
  return new Promise((resolve, reject) => {
    https.get(url, res => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => resolve(data));
    }).on('error', reject);
  });
}

// ── Fetch distances by wind direction (from coastline-model) ─────────
const FETCH_BY_DIR = {
  0: { nm: 0.3, desc: 'Blocked by harbor breakwall' },
  15: { nm: 1.5, desc: 'Inner Kahului Bay' },
  30: { nm: 5, desc: 'Across Kahului Bay' },
  45: { nm: 50, desc: 'Open channel toward Molokai' },
  60: { nm: 200, desc: 'Open Pacific (NE trades)' },
  75: { nm: 200, desc: 'Open Pacific' },
  90: { nm: 100, desc: 'Alenuihaha Channel' },
  105: { nm: 15, desc: 'Toward Hana coast' },
  120: { nm: 5, desc: 'East Maui blocks' },
};

// ── Shore geometry for downwind foiling ──────────────────────────────
// North shore runs roughly WSW-ENE. Shore normal at Kite Beach = 30° (NNE).
// For downwind foiling, you ride WITH the wind/swell direction.
// Best when swell direction is roughly parallel to shore (60-80°) so you
// can ride along the coast on organized bumps.
const SHORE_BEARING = 75; // approximate shore runs ~75° (ENE) at Kanaha/north shore
const SHORE_NORMAL = 30;  // points out to sea (NNE)

// ── SMB (Sverdrup-Munk-Bretschneider) wave estimation ────────────────
// Empirical method to estimate significant wave height from wind speed, fetch, duration
function estimateWindswell(windSpeedKts, fetchNm, durationHours) {
  if (!windSpeedKts || windSpeedKts < 5 || !fetchNm || fetchNm < 1) {
    return { height_m: 0, period_s: 0 };
  }

  const U = windSpeedKts * 0.5144; // m/s
  const F = fetchNm * 1852; // meters

  // Fetch-limited significant wave height (SMB shallow water approx)
  const Hs_fetch = 0.0016 * Math.sqrt(U * F);
  // Fetch-limited peak period
  const Tp_fetch = 0.286 * Math.pow(F / (9.81), 0.333) * Math.pow(U / F, 0.167);

  // Duration-limited (if wind hasn't blown long enough to fully develop)
  const t = durationHours * 3600;
  const Hs_dur = 0.0016 * Math.sqrt(U * Math.min(F, U * t * 0.7));

  // Take the smaller (limiting factor)
  const Hs = Math.min(Hs_fetch, Hs_dur);

  // Simple period estimate: Tp ≈ 0.45 * sqrt(fetch_km)
  const Tp = Math.min(8, Math.max(3, 0.45 * Math.sqrt(fetchNm * 1.852)));

  return {
    height_m: Math.round(Hs * 100) / 100,
    period_s: Math.round(Tp * 10) / 10,
  };
}

// ── Direction utilities ──────────────────────────────────────────────
function compassToText(deg) {
  if (deg == null) return '?';
  const dirs = ['N','NNE','NE','ENE','E','ESE','SE','SSE','S','SSW','SW','WSW','W','WNW','NW','NNW'];
  return dirs[Math.round(deg / 22.5) % 16];
}

function angleDiff(a, b) {
  let d = ((a - b) % 360 + 360) % 360;
  return d > 180 ? 360 - d : d;
}

function getFetch(windDirDeg) {
  // Find closest fetch entry
  const keys = Object.keys(FETCH_BY_DIR).map(Number).sort((a, b) => a - b);
  let closest = keys[0];
  let minDiff = 999;
  for (const k of keys) {
    const diff = angleDiff(windDirDeg, k);
    if (diff < minDiff) { minDiff = diff; closest = k; }
  }
  return FETCH_BY_DIR[closest];
}

// ── Windswell quality assessment ─────────────────────────────────────
function assessWindswellQuality(windDirDeg, windSpeedKts, windswellHt, windswellPeriod, windswellDir) {
  const result = {
    downwind_foil_score: 0,   // 0-5
    downwind_foil_rating: '',
    swell_organization: '',
    notes: [],
  };

  if (!windSpeedKts || windSpeedKts < 8) {
    result.downwind_foil_rating = 'NO-GO';
    result.notes.push('Too light for windswell generation');
    return result;
  }

  // 1. Wind direction quality for windswell at north shore
  //    Best: NE-ENE (45-75°) — long fetch, swell runs along shore
  //    OK: N-NE (0-45°) — swell more onshore
  //    Poor: E-ESE (90-120°) — short fetch, cross-shore, choppy
  const dirScore = (() => {
    if (windDirDeg >= 45 && windDirDeg <= 75) return 5;  // NE-ENE: perfect
    if (windDirDeg >= 30 && windDirDeg <= 90) return 4;  // NNE-E: good
    if (windDirDeg >= 15 && windDirDeg <= 105) return 3; // broader NE-ESE: ok
    if (windDirDeg >= 0 && windDirDeg <= 120) return 2;  // N-ESE: marginal
    return 1; // everything else: poor
  })();

  // 2. Fetch distance
  const fetch = getFetch(windDirDeg);
  const fetchScore = fetch.nm >= 100 ? 5 : fetch.nm >= 50 ? 4 : fetch.nm >= 20 ? 3 : fetch.nm >= 5 ? 2 : 1;

  // 3. Wind speed (for windswell generation)
  //    15-25kts: ideal for organized windswell without excessive chop
  //    <12: too light, minimal swell
  //    >30: big but chaotic
  const speedScore = (() => {
    if (windSpeedKts >= 15 && windSpeedKts <= 25) return 5;
    if (windSpeedKts >= 12 && windSpeedKts <= 30) return 4;
    if (windSpeedKts >= 10 && windSpeedKts <= 35) return 3;
    if (windSpeedKts >= 8) return 2;
    return 1;
  })();

  // 4. Swell organization (period consistency)
  //    Longer period windswell = more organized, easier to foil
  //    4-6s: choppy, short. 6-8s: organized, ideal. >8s: transitioning to groundswell
  const periodScore = (() => {
    if (!windswellPeriod) return 3; // neutral if unknown
    if (windswellPeriod >= 6 && windswellPeriod <= 9) return 5;
    if (windswellPeriod >= 5 && windswellPeriod <= 10) return 4;
    if (windswellPeriod >= 4) return 3;
    return 2;
  })();

  // 5. Swell height (for foilboarding)
  //    0.5-1.5m: ideal — enough energy to pump and glide, not overwhelming
  //    <0.3m: too flat. >2m: getting big, more advanced
  const heightScore = (() => {
    if (!windswellHt) return 3;
    if (windswellHt >= 0.5 && windswellHt <= 1.5) return 5;
    if (windswellHt >= 0.3 && windswellHt <= 2.0) return 4;
    if (windswellHt >= 0.2 && windswellHt <= 2.5) return 3;
    if (windswellHt > 2.5) return 2;
    return 1;
  })();

  // 6. Downwind angle — for foiling, want to ride roughly parallel to shore
  //    Swell direction relative to shore bearing determines ride angle
  const swellAngleToShore = windswellDir ? angleDiff(windswellDir, SHORE_BEARING) : null;
  const angleScore = (() => {
    if (swellAngleToShore == null) return 3;
    // 0° = parallel to shore (perfect downwind run)
    // 30° = slight angle (still great)
    // 60°+ = too cross-shore
    if (swellAngleToShore <= 20) return 5;
    if (swellAngleToShore <= 35) return 4;
    if (swellAngleToShore <= 50) return 3;
    if (swellAngleToShore <= 70) return 2;
    return 1;
  })();

  // Composite score (weighted)
  const weights = { dir: 2, fetch: 1.5, speed: 1.5, period: 1, height: 1.5, angle: 1.5 };
  const totalWeight = Object.values(weights).reduce((a, b) => a + b, 0);
  const rawScore = (dirScore * weights.dir + fetchScore * weights.fetch +
    speedScore * weights.speed + periodScore * weights.period +
    heightScore * weights.height + angleScore * weights.angle) / totalWeight;
  result.downwind_foil_score = Math.round(rawScore * 10) / 10;
  result.downwind_foil_rating = rawScore >= 4 ? 'EPIC' : rawScore >= 3.5 ? 'GOOD' : rawScore >= 2.5 ? 'FAIR' : rawScore >= 1.5 ? 'MARGINAL' : 'NO-GO';

  // Sub-scores for transparency
  result.sub_scores = {
    wind_direction: { score: dirScore, value: `${compassToText(windDirDeg)} (${windDirDeg}°)` },
    fetch: { score: fetchScore, value: `${fetch.nm}nm (${fetch.desc})` },
    wind_speed: { score: speedScore, value: `${windSpeedKts}kts` },
    swell_period: { score: periodScore, value: windswellPeriod ? `${windswellPeriod}s` : 'unknown' },
    swell_height: { score: heightScore, value: windswellHt ? `${windswellHt}m` : 'unknown' },
    downwind_angle: { score: angleScore, value: swellAngleToShore != null ? `${swellAngleToShore}° off shore` : 'unknown' },
  };

  // Organization assessment
  if (windswellPeriod && windswellPeriod >= 6) {
    result.swell_organization = 'organized';
    result.notes.push('Well-organized windswell — clean bumps for foiling');
  } else if (windswellPeriod && windswellPeriod >= 4.5) {
    result.swell_organization = 'moderate';
    result.notes.push('Moderate windswell organization — rideable but choppy');
  } else {
    result.swell_organization = 'choppy';
    result.notes.push('Short period chop — harder to connect bumps');
  }

  // Direction-specific notes
  if (windDirDeg >= 45 && windDirDeg <= 70) {
    result.notes.push('NE trades producing ideal side-shore windswell — clean lines along coast');
  } else if (windDirDeg >= 70 && windDirDeg <= 100) {
    result.notes.push('Easterly trades — windswell more cross-shore, less organized for downwind runs');
  } else if (windDirDeg >= 30 && windDirDeg <= 45) {
    result.notes.push('NNE wind — windswell slightly onshore, short runs before hitting beach');
  }

  // Height notes for foiling
  if (windswellHt && windswellHt >= 0.8 && windswellHt <= 1.5) {
    result.notes.push(`${windswellHt}m windswell — perfect size for foil glides`);
  } else if (windswellHt && windswellHt >= 1.5) {
    result.notes.push(`${windswellHt}m windswell — big bumps, experienced foilers`);
  } else if (windswellHt && windswellHt < 0.4) {
    result.notes.push(`${windswellHt}m windswell — too small for effective gliding`);
  }

  return result;
}

// ── Parse NDBC spectral file ─────────────────────────────────────────
function parseSpecLine(line) {
  const cols = line.trim().split(/\s+/);
  if (cols.length < 15) return null;
  const v = (i) => cols[i] !== 'MM' ? parseFloat(cols[i]) : null;
  const sv = (i) => cols[i] !== 'MM' ? cols[i] : null;

  return {
    time_utc: `${cols[0]}-${cols[1]}-${cols[2]}T${cols[3]}:${cols[4]}Z`,
    total_wave_ht_m: v(5),
    swell_ht_m: v(6),        // groundswell
    swell_period_s: v(7),
    wind_wave_ht_m: v(8),    // windswell
    wind_wave_period_s: v(9),
    swell_dir: sv(10),
    wind_wave_dir: sv(11),
    steepness: sv(12),
    avg_period_s: v(13),
    mean_wave_dir_deg: v(14),
  };
}

function compassTextToDeg(text) {
  const map = { N:0,NNE:22.5,NE:45,ENE:67.5,E:90,ESE:112.5,SE:135,SSE:157.5,
    S:180,SSW:202.5,SW:225,WSW:247.5,W:270,WNW:292.5,NW:315,NNW:337.5 };
  return map[text] ?? null;
}

// ── Main ─────────────────────────────────────────────────────────────
async function main() {
  process.stderr.write('windswell: fetching Pauwela buoy spectral data...\n');

  // Fetch spectral data from buoy network
  // - 51205 Pauwela: primary north shore reference (truth)
  // - 51202 Mokapu: Oahu cross-reference
  // - 51001 NW Hawaii: groundswell early warning (NW swell arrives here first)
  // - 51000 N Hawaii: groundswell early warning (N/NNE swell arrives here first)
  const buoys = {};
  for (const [id, name] of [['51205', 'Pauwela, Maui'], ['51202', 'Mokapu, Oahu'], ['51001', 'NW Hawaii (groundswell early warning)'], ['51000', 'N Hawaii (groundswell early warning)']]) {
    try {
      const specText = await fetchText(`https://www.ndbc.noaa.gov/data/realtime2/${id}.spec`);
      const lines = specText.trim().split('\n');
      const dataLines = lines.filter(l => !l.startsWith('#'));
      buoys[id] = {
        name,
        latest: parseSpecLine(dataLines[0]),
        // Grab last 12 readings (~6 hours) for trend
        recent: dataLines.slice(0, 12).map(parseSpecLine).filter(Boolean),
      };
    } catch (e) {
      process.stderr.write(`  ${id} failed: ${e.message}\n`);
    }
  }

  // Get current wind from Kanaha (use WeatherFlow API via simple fetch)
  // For standalone use, accept wind as env vars or use a reasonable default
  const windSpeedKts = parseFloat(process.env.WIND_SPEED_KTS || '0');
  const windDirDeg = parseFloat(process.env.WIND_DIR_DEG || '0');

  // Primary analysis from Pauwela (closest to north shore action)
  const pauwela = buoys['51205']?.latest;
  const mokapu = buoys['51202']?.latest;

  // Current windswell conditions (from buoy spectral data)
  const windswellObs = pauwela ? {
    source: 'NDBC 51205 Pauwela',
    time_utc: pauwela.time_utc,
    total_wave_ht_m: pauwela.total_wave_ht_m,
    groundswell: {
      height_m: pauwela.swell_ht_m,
      period_s: pauwela.swell_period_s,
      direction: pauwela.swell_dir,
      direction_deg: compassTextToDeg(pauwela.swell_dir),
      note: 'Distant storm swell — independent of local wind',
    },
    windswell: {
      height_m: pauwela.wind_wave_ht_m,
      period_s: pauwela.wind_wave_period_s,
      direction: pauwela.wind_wave_dir,
      direction_deg: compassTextToDeg(pauwela.wind_wave_dir),
      note: 'Locally generated by trade winds — builds/fades with wind',
    },
    steepness: pauwela.steepness,
  } : null;

  // Windswell trend (is it building or fading?)
  let windswellTrend = null;
  const pauwelaRecent = buoys['51205']?.recent;
  if (pauwelaRecent && pauwelaRecent.length >= 4) {
    const recent2h = pauwelaRecent.slice(0, 4); // ~2 hours
    const older2h = pauwelaRecent.slice(4, 8);  // 2-4 hours ago

    const recentAvgHt = recent2h.filter(r => r.wind_wave_ht_m).reduce((a, r) => a + r.wind_wave_ht_m, 0) / recent2h.filter(r => r.wind_wave_ht_m).length || 0;
    const olderAvgHt = older2h.filter(r => r.wind_wave_ht_m).reduce((a, r) => a + r.wind_wave_ht_m, 0) / Math.max(1, older2h.filter(r => r.wind_wave_ht_m).length) || 0;

    const changePct = olderAvgHt > 0 ? Math.round(((recentAvgHt - olderAvgHt) / olderAvgHt) * 100) : 0;
    windswellTrend = {
      recent_avg_ht_m: Math.round(recentAvgHt * 100) / 100,
      older_avg_ht_m: Math.round(olderAvgHt * 100) / 100,
      change_pct: changePct,
      trend: changePct > 15 ? 'building' : changePct < -15 ? 'fading' : 'steady',
      note: changePct > 15 ? 'Windswell building — trades have been strengthening'
        : changePct < -15 ? 'Windswell fading — trades weakening or shifting direction'
        : 'Windswell holding steady',
    };
  }

  // SMB estimate (what windswell should today's wind produce?)
  const fetch = windDirDeg ? getFetch(windDirDeg) : null;
  const smbEstimate = windSpeedKts > 0 && fetch ? estimateWindswell(windSpeedKts, fetch.nm, 6) : null;

  // Quality assessment for downwind foiling
  const windswellDirDeg = pauwela ? compassTextToDeg(pauwela.wind_wave_dir) : null;
  const quality = assessWindswellQuality(
    windDirDeg || windswellDirDeg,
    windSpeedKts || null,
    pauwela?.wind_wave_ht_m,
    pauwela?.wind_wave_period_s,
    windswellDirDeg
  );

  // Cross-reference with Mokapu
  const crossRef = mokapu ? {
    source: 'NDBC 51202 Mokapu',
    windswell_ht_m: mokapu.wind_wave_ht_m,
    windswell_period_s: mokapu.wind_wave_period_s,
    windswell_dir: mokapu.wind_wave_dir,
    groundswell_ht_m: mokapu.swell_ht_m,
    groundswell_period_s: mokapu.swell_period_s,
    note: 'Oahu buoy — similar exposure, confirms regional windswell pattern',
  } : null;

  // Groundswell early warning: compare NW/N Hawaii buoys to Pauwela
  // These buoys sit north of the island chain — north Pacific swell arrives there first.
  const nwBuoy = buoys['51001']?.latest;
  const nBuoy = buoys['51000']?.latest;
  const groundswellEarlyWarning = (() => {
    const warnings = [];
    const pauwelaSwellHt = pauwela?.swell_ht_m || 0;
    const pauwelaSwellPeriod = pauwela?.swell_period_s || 0;

    for (const [label, id, buoy] of [['NW Hawaii (51001)', '51001', nwBuoy], ['N Hawaii (51000)', '51000', nBuoy]]) {
      if (!buoy?.swell_ht_m) continue;
      const htRatio = pauwelaSwellHt > 0 ? buoy.swell_ht_m / pauwelaSwellHt : null;

      const entry = {
        source: label,
        swell_ht_m: buoy.swell_ht_m,
        swell_period_s: buoy.swell_period_s,
        swell_dir: buoy.swell_dir,
        vs_pauwela_ht_ratio: htRatio ? Math.round(htRatio * 100) / 100 : null,
        signal: 'none',
        note: '',
      };

      if (htRatio && htRatio > 1.5 && buoy.swell_ht_m > 1.0) {
        entry.signal = 'new_swell_incoming';
        entry.note = `⚠️ ${label} showing ${buoy.swell_ht_m}m swell vs Pauwela ${pauwelaSwellHt}m — new swell incoming`;
      } else if (htRatio && htRatio > 1.2) {
        entry.signal = 'swell_building';
        entry.note = `${label} swell slightly larger (${buoy.swell_ht_m}m vs ${pauwelaSwellHt}m) — may be building`;
      } else if (buoy.swell_period_s && buoy.swell_period_s > 14 && pauwelaSwellPeriod < 12) {
        entry.signal = 'long_period_incoming';
        entry.note = `${label} showing long-period ${buoy.swell_period_s}s swell — new groundswell arriving`;
      } else {
        entry.signal = 'consistent';
        entry.note = 'Consistent with Pauwela — no new swell incoming';
      }

      // Trend from recent readings
      const recent = buoys[id]?.recent;
      if (recent && recent.length >= 4) {
        const new2h = recent.slice(0, 4).filter(r => r.swell_ht_m).map(r => r.swell_ht_m);
        const old2h = recent.slice(4, 8).filter(r => r.swell_ht_m).map(r => r.swell_ht_m);
        if (new2h.length && old2h.length) {
          const newAvg = new2h.reduce((a, b) => a + b, 0) / new2h.length;
          const oldAvg = old2h.reduce((a, b) => a + b, 0) / old2h.length;
          entry.trend_pct = Math.round(((newAvg - oldAvg) / oldAvg) * 100);
          entry.trend = entry.trend_pct > 20 ? 'rising_fast' : entry.trend_pct > 5 ? 'rising' : entry.trend_pct < -20 ? 'dropping_fast' : entry.trend_pct < -5 ? 'dropping' : 'steady';
        }
      }

      warnings.push(entry);
    }
    return warnings.length > 0 ? warnings : null;
  })();

  // Windswell forecast based on wind prediction taper
  // As wind tapers through afternoon, windswell lags ~1-2 hours behind wind
  const windswellForecast = [];
  if (windSpeedKts > 0 && fetch) {
    for (let h = 12; h <= 19; h++) {
      // Simple model: windswell height responds to wind with 1-2h lag
      // As thermal fades, windswell fades ~1h later
      const laggedWindFactor = h <= 14 ? 1.0 : Math.max(0.3, 1.0 - (h - 15) * 0.15);
      const estWind = windSpeedKts * laggedWindFactor;
      const est = estimateWindswell(estWind, fetch.nm, Math.min(h - 6, 8));
      windswellForecast.push({
        hour_hst: h,
        estimated_wind_kts: Math.round(estWind),
        windswell_ht_m: est.height_m,
        windswell_period_s: est.period_s,
        note: h <= 14 ? 'Peak thermal → peak windswell' :
          h <= 17 ? 'Thermal fading → windswell lagging 1-2h behind wind' :
          'Evening — windswell fading with trades',
      });
    }
  }

  const output = {
    source: 'windswell-analysis',
    fetched_utc: new Date().toISOString(),
    location: 'Kanaha Beach / North Shore Maui',
    shore_bearing_deg: SHORE_BEARING,
    shore_normal_deg: SHORE_NORMAL,

    current_conditions: windswellObs,
    windswell_trend: windswellTrend,
    smb_estimate: smbEstimate ? {
      ...smbEstimate,
      wind_kts: windSpeedKts,
      wind_dir: compassToText(windDirDeg),
      fetch_nm: fetch.nm,
      fetch_desc: fetch.desc,
      note: 'Theoretical windswell from current wind (SMB method)',
    } : null,

    downwind_foiling: quality,
    cross_reference: crossRef,
    groundswell_early_warning: groundswellEarlyWarning,
    windswell_forecast: windswellForecast.length > 0 ? windswellForecast : null,

    summary: {
      windswell: pauwela ? `${pauwela.wind_wave_ht_m}m @ ${pauwela.wind_wave_period_s}s from ${pauwela.wind_wave_dir}` : 'unknown',
      groundswell: pauwela ? `${pauwela.swell_ht_m}m @ ${pauwela.swell_period_s}s from ${pauwela.swell_dir}` : 'unknown',
      trend: windswellTrend?.trend || 'unknown',
      foil_rating: quality.downwind_foil_rating,
      foil_score: quality.downwind_foil_score,
    },
  };

  console.log(JSON.stringify(output, null, 2));
}

main().catch(e => { console.error(e); process.exit(1); });
